#include <stdio.h>
#include <math.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N, X; scanf("%d %d", &N, &X);
        long long sum = 0; int mx = 0;
        for(int i=0;i<N;i++){
            int h; scanf("%d", &h);
            sum += (h + X - 1) / X; // ceil division
            if(h > mx) mx = h;
        }
        long long ans = sum < mx ? sum : mx;
        printf("%lld\n", ans);
    }
    return 0;
}

