int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N, X; cin>>N>>X;
        long long sum = 0; int mx = 0;
        for(int i=0;i<N;++i){
            int h; cin>>h;
            sum += (h + X - 1) / X; // ceil
            mx = max(mx, h);
        }
        cout << min(sum, (long long)mx) << '\n';
    }
    return 0;
}

