#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it)); X = int(next(it))
        sum_hits = 0
        mx = 0
        for _ in range(N):
            h = int(next(it))
            sum_hits += (h + X - 1) // X
            if h > mx:
                mx = h
        out.append(str(min(sum_hits, mx)))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

